<?php
namespace App\Http\Controllers;use App\Models\BillingDocument;use Illuminate\Http\Request;
class AccountBillingController extends Controller{public function index(Request $r){$d=$this->owned($r)->with('order')->latest('issued_at')->get();return view('account.billing.index',['documents'=>$d,'issuedAmount'=>$d->where('status','issued')->sum('total_amount'),'paidAmount'=>$d->where('status','paid')->sum('total_amount')]);}public function show(Request $r,BillingDocument $billingDocument){abort_unless($this->owned($r)->whereKey($billingDocument)->exists(),404);return view('account.billing.show',['document'=>$billingDocument->load(['order.scenario','customer','paymentRecords'])]);}private function owned(Request $r){return BillingDocument::query()->whereIn('status',['issued','paid','refunded'])->where(fn($q)=>$q->where('customer_id',$r->user()->id)->orWhereHas('order',fn($o)=>$o->where('customer_id',$r->user()->id)));}}